mapper.select:
SELECT ID, PAGE_NAME, PAGE_LABEL, PAGE_SORT, CREATE_TIME, UPDATE_TIME, (SELECT USERNAME FROM user u WHERE u.ID = p.CREATE_USER) AS CREATE_USERNAME, (SELECT USERNAME FROM user u WHERE u.ID = p.UPDATE_USER) AS UPDATE_USERNAME FROM page p
AND PAGE_NAME LIKE #{pageNameBind}
AND PAGE_LABEL LIKE #{pageLabelBind}
ORDER BY PAGE_SORT
